import React, { useEffect, useRef } from 'react';
import './Hero.css';

export default function Hero() {
  const ref = useRef(null);

  useEffect(() => {
    const el = ref.current;
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) el.querySelectorAll('.reveal').forEach(r => r.classList.add('visible'));
    }, { threshold: 0.1 });
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  return (
    <section className="hero" id="hero" ref={ref}>
      <div className="hero-bg" />
      <div className="hero-grid-lines" />
      <div className="hero-bg-text">EDIT</div>

      <div className="hero-stats-col">
        <div className="hs-item reveal reveal-d1">
          <div className="hs-n">4K</div>
          <div className="hs-l">Max Res</div>
        </div>
        <div className="hs-item reveal reveal-d2">
          <div className="hs-n">24fps</div>
          <div className="hs-l">Cinematic</div>
        </div>
        <div className="hs-item reveal reveal-d3">
          <div className="hs-n">48hr</div>
          <div className="hs-l">Turnaround</div>
        </div>
      </div>

      <div className="hero-content">
        <p className="hero-eyebrow reveal">
          <span className="rec">
            <span className="rec-dot" />REC
          </span>
          &nbsp;·&nbsp; Video Editor &amp; Colorist
        </p>
        <h2 className="hero-title reveal">
          STORIES<br />
          THAT <span className="lime">HIT</span><br />
          <span className="stroke">DIFFERENT</span>
        </h2>
        <p className="hero-sub reveal">
          Cinematic edits for creators who want to stand out
        </p>
        <div className="hero-btns reveal">
          <button className="btn-lime">
            <svg width="10" height="10" viewBox="0 0 10 10" fill="currentColor">
              <polygon points="2,1 9,5 2,9" />
            </svg>
            Watch Reel
          </button>
          <a href="#work" className="btn-ghost">See My Work</a>
        </div>
      </div>

      <div className="hero-scroll">Scroll</div>
    </section>
  );
}
